/**
 * Atlas Tile
 * 
 * High-fidelity logic for interactive tiles.
 * Handles selection states, grouping (single-select), and keyboard accessibility.
 */

export class Tile {
  constructor(element) {
    if (!element) return;
    this.element = typeof element === 'string' ? document.querySelector(element) : element;
    
    // Guard against double-initialization
    if (this.element.__atlas_init) return this.element.__atlas_instance;
    this.element.__atlas_init = true;

    this.selectedClass = 'tile-selected';
    this.disabledClass = 'tile-disabled';
    this.groupContainer = this.element.closest('[data-tile-group]');
    
    this.callbacks = { change: [] };

    this.init();
    this.element.__atlas_instance = this;
  }

  init() {
    // Accessibility: Ensure it's reachable and identify as a button/tab
    if (!this.element.hasAttribute('tabindex') && !this.element.disabled) {
      this.element.setAttribute('tabindex', '0');
    }
    if (!this.element.hasAttribute('role')) {
      this.element.setAttribute('role', 'button');
    }

    const triggerSelection = (e) => {
      if (this.isDisabled()) {
        e.preventDefault();
        return;
      }
      this.toggle();
    };

    this.element.addEventListener('click', triggerSelection);
    this.element.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        triggerSelection(e);
      }
    });
  }

  /**
   * Toggle selected state
   * If in a group, unselect siblings first
   */
  toggle(forceState) {
    const isNowSelected = forceState !== undefined ? forceState : !this.isSelected();

    if (isNowSelected && this.groupContainer) {
      // Single-select logic for groups
      const siblings = this.groupContainer.querySelectorAll('.tile');
      siblings.forEach(node => {
        if (node !== this.element && node.__atlas_instance) {
          node.__atlas_instance.toggle(false);
        } else if (node !== this.element) {
          node.classList.remove(this.selectedClass);
          node.setAttribute('aria-pressed', 'false');
        }
      });
    }

    this.element.classList.toggle(this.selectedClass, isNowSelected);
    this.element.setAttribute('aria-pressed', isNowSelected ? 'true' : 'false');
    
    if (isNowSelected || forceState === false) {
      this.dispatch();
    }
  }

  isSelected() {
    return this.element.classList.contains(this.selectedClass);
  }

  isDisabled() {
    return (
      this.element.disabled || 
      this.element.classList.contains(this.disabledClass) || 
      this.element.hasAttribute('disabled')
    );
  }

  get value() {
    // Priority: data-value > text content
    return this.element.getAttribute('data-value') || this.element.textContent.trim();
  }

  set selected(val) {
    this.toggle(!!val);
  }

  on(event, callback) {
    if (this.callbacks[event]) {
      this.callbacks[event].push(callback);
    }
    return this;
  }

  dispatch() {
    const isSelected = this.isSelected();
    const val = this.value;

    this.callbacks.change.forEach(cb => cb(val, isSelected));

    const event = new CustomEvent('tile-change', {
      detail: { value: val, selected: isSelected },
      bubbles: true
    });
    this.element.dispatchEvent(event);
  }
}

/**
 * Factory initialization
 */
export function initTile(element) {
  return new Tile(element);
}
