import { initOtpInput } from './components/otp-input';
import { initFormField } from './components/form-field';
import { initSegmentedControl } from './components/segmented-control';
import { initTile } from './components/tile';

/**
 * Scans the DOM and initializes all Atlas Design System components.
 * @param {ParentNode} root - The root element to scan (defaults to document).
 */
export function initAtlas(root = document) {
  // Initialize all OTP groups
  root.querySelectorAll('.otp-group').forEach(group => {
    initOtpInput(group);
  });

  // Initialize all Form Fields
  root.querySelectorAll('.form-field').forEach(field => {
    initFormField(field);
  });

  // Initialize all Segmented Controls
  root.querySelectorAll('.segmented-control').forEach(control => {
    initSegmentedControl(control);
  });

  // Initialize all Tiles
  root.querySelectorAll('.tile').forEach(tile => {
    initTile(tile);
  });
}

/**
 * Setup MutationObserver to handle dynamic content (Better DX for SPAs)
 */
function setupObserver() {
  if (typeof document === 'undefined') return;

  const observer = new MutationObserver((mutations) => {
    mutations.forEach(mutation => {
      mutation.addedNodes.forEach(node => {
        if (node.nodeType === 1) { // Element node
          // If the added node is a component or contains components, re-scan it
          if (
            node.matches('.otp-group, .form-field, .segmented-control, .tile') ||
            node.querySelector('.otp-group, .form-field, .segmented-control, .tile')
          ) {
            initAtlas(node);
          }
        }
      });
    });
  });

  observer.observe(document.body, { childList: true, subtree: true });
}

// Automatically initialize on DOMContentLoaded and setup observer
if (typeof document !== 'undefined') {
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => {
      initAtlas();
      setupObserver();
    });
  } else {
    initAtlas();
    setupObserver();
  }
}
